const r=document.querySelectorAll(".credits-wrapper"),d=e=>{const t=e.querySelector(".credits-collapse-wrapper"),s=e.querySelector(".credits-content-wrapper");if(!t||!s)return;const l=e.classList.contains("is-open"),i=s.scrollHeight,o=s.scrollWidth,c="0.35s",n="cubic-bezier(0.22, 1, 0.36, 1)";if(t.style.overflow="hidden",t.style.transition=`height ${c} ${n}, width ${c} ${n}`,l){t.style.height=i+"px",t.style.width=o+"px",t.offsetHeight,requestAnimationFrame(()=>{t.style.height="0px",t.style.width="0px"}),e.classList.remove("is-open");return}t.style.height="0px",t.style.width="0px",t.offsetHeight,requestAnimationFrame(()=>{t.style.height=i+"px",t.style.width=o+"px"}),e.classList.add("is-open")};r.forEach(e=>{e.addEventListener("click",()=>d(e))});window.addEventListener("resize",()=>{r.forEach(e=>{if(!e.classList.contains("is-open"))return;const t=e.querySelector(".credits-collapse-wrapper"),s=e.querySelector(".credits-content-wrapper");!t||!s||(t.style.height=s.scrollHeight+"px",t.style.width=s.scrollWidth+"px")})});
